-- Program: Shred Program
-- Category: Fat Loss -> fat_loss
-- Priority: High
-- Durations: [2, 4, 6, 8, 12], Sessions: [4, 4, 5, 5, 5]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Shred Program',
    'A comprehensive fat loss program combining strength training with metabolic conditioning. Designed for those in a caloric deficit who want to maximize fat burning while preserving lean muscle mass. Features circuits, supersets, and HIIT finishers.',
    'fat_loss',
    'all_levels',
    12,
    5,
    'full_body',
    ARRAY['Increase maximal strength', 'Progressive overload', 'Maximize muscle hypertrophy', 'Time under tension', 'Maximize calorie burn']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Shred Program - 2w 4x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    2,
    'Shred Program - 2w 4x/wk',
    'fat_loss',
    4,
    60,
    ARRAY['Increase maximal strength', 'Progressive overload', 'Maximize muscle hypertrophy', 'Time under tension', 'Maximize calorie burn']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Shred Program'
ON CONFLICT DO NOTHING;

